export async function toggleFollow(targetUsername: string) {
    const user = await prisma.user.findFirst();
    if (!user) throw new Error('No user found');

    const target = await prisma.user.findUnique({ where: { username: targetUsername } });
    if (!target) throw new Error('Target user not found');

    // Check existing follow
    const existing = await prisma.follows.findFirst({
        where: {
            followerId: user.id,
            followingId: target.id,
        }
    });

    if (existing) {
        await prisma.follows.delete({ where: { id: existing.id } });
    } else {
        await prisma.follows.create({ data: { followerId: user.id, followingId: target.id } });

        // send notification (best effort)
        if (target.id !== user.id) {
            await sendNotification(target.id, 'follow', {
                actorId: user.id,
                actorName: user.username || 'User'
            });
        }
    }

    // Revalidate profile routes
    revalidatePath('/profile');
}

export async function updateUserSettings(data: {
    fullName?: string;
    username?: string;
    bio?: string;
    website?: string;
    isPrivate?: boolean;
    avatar?: string;
}) {
    try {
        let user = await prisma.user.findFirst({
            where: { username: 'antigravity_dev' }
        });

        if (!user) user = await prisma.user.findFirst();
        if (!user) throw new Error('User not found');

        const updatedUser = await prisma.user.update({
            where: { id: user.id },
            data: {
                fullName: data.fullName,
                username: data.username,
                bio: data.bio,
                website: data.website,
                // @ts-ignore
                isPrivate: data.isPrivate,
                avatar: data.avatar,
            }
        });

        revalidatePath('/settings');
        revalidatePath('/profile');
        revalidatePath('/');

        return { success: true, user: updatedUser };
    } catch (error) {
        console.error('Update Settings Error:', error);
        return { success: false, error: (error as Error).message };
    }
}

import { NextResponse } from 'next/server';
import prisma from '@/lib/prisma';
import { cookies } from 'next/headers';

// Mock Authentication - In a real app, use NextAuth or similar
// This simulates logging in as the main dev user or creating it if missing
export async function POST(req: Request) {
    try {
        const { username } = await req.json();

        // Find or Create user
        let user = await prisma.user.findUnique({
            where: { username }
        });

        if (!user && username === 'antigravity_dev') {
            user = await prisma.user.create({
                data: {
                    username: 'antigravity_dev',
                    email: 'dev@antigravity.com',
                    password: 'mock_password_hash', // In real app, hash this!
                    fullName: 'Antigravity Developer',
                    avatar: 'https://i.pravatar.cc/150?u=antigravity',
                    bio: 'Building the next gen social app.',
                    isVerified: true
                }
            });
        }

        if (!user) {
            return NextResponse.json({ error: 'User not found' }, { status: 404 });
        }

        // Set a simple cookie session (Insecure for prod, fine for MVP demo)
        (await cookies()).set('userId', user.id, { httpOnly: true });

        return NextResponse.json({ success: true, user });
    } catch (error) {
        return NextResponse.json({ error: 'Login failed' }, { status: 500 });
    }
}

export async function GET() {
    const cookieStore = await cookies();
    const userId = cookieStore.get('userId')?.value;

    if (!userId) {
        return NextResponse.json({ authenticated: false }, { status: 401 });
    }

    const user = await prisma.user.findUnique({
        where: { id: userId },
        select: {
            id: true,
            username: true,
            avatar: true,
            fullName: true,
            email: true
        }
    });

    if (!user) {
        return NextResponse.json({ authenticated: false }, { status: 401 });
    }

    return NextResponse.json({ authenticated: true, user });
}

import { NextResponse } from 'next/server';
import prisma from '@/lib/prisma';
import { FeedService } from '@/services/feed-service';

export const dynamic = 'force-dynamic';

export async function GET(request: Request) {
    try {
        // Authenticate the cron request (in prod using a secret key)
        const authHeader = request.headers.get('Authorization');
        // Simple check: if needed, compare with CRON_SECRET env
        // if (authHeader !== `Bearer ${process.env.CRON_SECRET}`) ...

        // 1. Identify "Active Users"
        // Algorithm: Users who have logged in recently, or posted recently.
        // For simplicity: Users who have posted or liked in the last 24 hours.
        // OR just all users for this demo if small user base.

        const oneDayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000);

        const activeUsers = await prisma.user.findMany({
            where: {
                OR: [
                    { posts: { some: { createdAt: { gte: oneDayAgo } } } },
                    { likes: { some: { createdAt: { gte: oneDayAgo } } } },
                    // Or simply recent logins if tracked
                    { username: 'antigravity_dev' } // Always include the dev
                ]
            },
            select: { id: true, username: true }
        });

        // 2. Pre-compute feeds
        // Run in parallel but limited concurrency if large
        const results = await Promise.all(
            activeUsers.map(async (user) => {
                try {
                    await FeedService.precomputeFeed(user.id);
                    return { userId: user.id, status: 'success' };
                } catch (e) {
                    return { userId: user.id, status: 'failed', error: String(e) };
                }
            })
        );

        return NextResponse.json({
            message: 'Feed pre-computation complete',
            processed: results.length,
            details: results
        });

    } catch (error) {
        console.error('Cron Job Failed:', error);
        return NextResponse.json({ error: 'Internal Server Error' }, { status: 500 });
    }
}

import { NextResponse } from 'next/server';
import prisma from '@/lib/prisma';
import { FeedService } from '@/services/feed-service';
import { getCassandraClient } from '@/lib/cassandra';
import { types } from 'cassandra-driver';
import { MOCK_POSTS } from '@/constants/mockData';

// GET all posts with ranking algorithm
// GET all posts with ranking algorithm
export async function GET(request: Request) {
    try {
        const { searchParams } = new URL(request.url);
        const page = parseInt(searchParams.get('page') || '1');
        const limit = parseInt(searchParams.get('limit') || '10');

        // 1. Identify current user (Simulated)
        // In a real app, this would come from session/auth
        const currentUser = await prisma.user.findFirst({
            include: { following: true }
        });

        if (!currentUser) {
            // Fallback: Just get latest posts if no user
            const skip = (page - 1) * limit;
            const posts = await prisma.post.findMany({
                include: {
                    user: { select: { username: true, avatar: true, fullName: true } },
                    likes: true,
                    comments: { include: { user: { select: { username: true } } } },
                    media: { orderBy: { order: 'asc' } }
                },
                orderBy: { createdAt: 'desc' },
                skip: skip,
                take: limit
            });

            // Map back to legacy format for clients expecting 'image'
            const mappedPosts = posts.map(p => ({
                ...p,
                image: p.media?.[0]?.url || ''
            }));

            if (!posts || posts.length === 0) {
                const fallback = MOCK_POSTS.map(p => ({
                    id: p.id,
                    caption: p.caption,
                    image: p.image,
                    createdAt: p.createdAt,
                    user: { username: p.user.username, avatar: p.user.avatar, fullName: p.user.name },
                    likes: [],
                    comments: [],
                }));
                return NextResponse.json(fallback);
            }
            return NextResponse.json(mappedPosts);
        }

        // 2. Delegate to FeedService
        const rankedFeed = await FeedService.generateFeed(currentUser.id, page, limit);

        return NextResponse.json(rankedFeed);
    } catch (error) {
        console.error('API Error (GET /api/posts):', error);
        // Fallback to mock posts when DB/Prisma isn't available
        try {
            const fallback = MOCK_POSTS.map(p => ({
                id: p.id,
                caption: p.caption,
                image: p.image,
                createdAt: p.createdAt,
                user: { username: p.user.username, avatar: p.user.avatar, fullName: p.user.name },
                likes: [],
                comments: [],
            }));
            return NextResponse.json(fallback);
        } catch (err) {
            return NextResponse.json({ error: 'Failed to fetch posts' }, { status: 500 });
        }
    }
}

// POST create a new post
export async function POST(request: Request) {
    try {
        const body = await request.json();
        const { caption, image, media, userId, location } = body;

        const mediaToUpload = media || (image ? [{ url: image, type: 'IMAGE' }] : []);

        if (mediaToUpload.length === 0) {
            return NextResponse.json({ error: 'At least one media item is required' }, { status: 400 });
        }

        // Identify target user
        let targetUserId = userId;
        if (!targetUserId) {
            const defaultUser = await prisma.user.findFirst();
            if (!defaultUser) {
                return NextResponse.json({ error: 'No users exist in the system' }, { status: 400 });
            }
            targetUserId = defaultUser.id;
        }

        const newPost = await prisma.post.create({
            data: {
                caption,
                location,
                userId: targetUserId,
                media: {
                    create: mediaToUpload.map((m: any, idx: number) => ({
                        url: m.url,
                        type: m.type || 'IMAGE',
                        order: idx
                    }))
                }
            },
            include: {
                user: true,
                media: true
            }
        });

        return NextResponse.json(newPost, { status: 201 });
    } catch (error) {
        console.error('API Error (POST /api/posts):', error);
        return NextResponse.json({ error: 'Failed to create post' }, { status: 500 });
    }
}

import { NextResponse } from 'next/server';
import prisma from '@/lib/prisma';
import { MOCK_SHOTS } from '@/constants/mockData';

export async function GET(request: Request) {
    try {
        const { searchParams } = new URL(request.url);
        const page = parseInt(searchParams.get('page') || '1');
        const limit = parseInt(searchParams.get('limit') || '10');
        const skip = (page - 1) * limit;

        const shots = await prisma.shot.findMany({
            include: {
                user: {
                    select: {
                        username: true,
                        avatar: true,
                    }
                },
                likes: true,
                comments: {
                    include: {
                        user: {
                            select: {
                                username: true,
                                avatar: true,
                            }
                        }
                    }
                },
            },
            orderBy: {
                createdAt: 'desc',
            },
            skip,
            take: limit
        });
        // If no shots found in DB, fall back to mock data
        if (!shots || shots.length === 0) {
            const fallback = MOCK_SHOTS.map(s => ({
                id: String(s.id),
                video: s.video,
                caption: s.caption,
                createdAt: new Date().toISOString(),
                user: {
                    username: s.username,
                    avatar: s.avatar,
                },
                likes: [],
                comments: [],
            }));
            return NextResponse.json(fallback);
        }

        return NextResponse.json(shots);
    } catch (error) {
        // If Prisma or DB is not available, return mock shots so frontend still works
        try {
            const fallback = MOCK_SHOTS.map(s => ({
                id: String(s.id),
                video: s.video,
                caption: s.caption,
                createdAt: new Date().toISOString(),
                user: {
                    username: s.username,
                    avatar: s.avatar,
                },
                likes: [],
                comments: [],
            }));
            return NextResponse.json(fallback);
        } catch (err) {
            return NextResponse.json({ error: 'Failed to fetch shots' }, { status: 500 });
        }
    }
}

export async function POST(request: Request) {
    try {
        const body = await request.json();
        const { video, caption, userId } = body;

        if (!video) {
            return NextResponse.json({ error: 'Video URL is required' }, { status: 400 });
        }

        let targetUserId = userId;
        if (!targetUserId) {
            const user = await prisma.user.findFirst();
            if (!user) return NextResponse.json({ error: 'User required' }, { status: 400 });
            targetUserId = user.id;
        }

        const shot = await prisma.shot.create({
            data: {
                video,
                caption,
                userId: targetUserId,
            }
        });

        return NextResponse.json(shot, { status: 201 });
    } catch (error) {
        return NextResponse.json({ error: 'Failed to create shot' }, { status: 500 });
    }
}

import { NextResponse } from 'next/server';
import prisma from '@/lib/prisma';
import { MOCK_STORIES } from '@/constants/mockData';

export async function GET() {
    try {
        // 1. Identify current user (Simulated)
        const currentUser = await prisma.user.findFirst({
            include: { following: true }
        });

        if (!currentUser) {
            // Fallback to mock stories when no DB user
            const fallback = MOCK_STORIES.map(s => ({
                id: s.id,
                user: s.user,
                slides: s.slides,
                hasViewed: s.hasViewed,
            }));
            return NextResponse.json(fallback);
        }

        const followingIds = currentUser.following.map(f => f.followingId);
        const userIdsToFetch = [...followingIds, currentUser.id];

        // 2. Fetch Stories
        // Stories disappear after 24 hours usually, but we'll use expiresAt
        const now = new Date();

        const stories = await prisma.story.findMany({
            where: {
                userId: { in: userIdsToFetch },
                expiresAt: { gt: now }
            },
            include: {
                user: {
                    select: {
                        username: true,
                        avatar: true
                    }
                }
            },
            orderBy: {
                createdAt: 'desc'
            }
        });

        // 3. Group by User (Algorithm: Stories are consumed per user)
        // We want to return a list of users who have stories, with their stories attached
        // But the current frontend StoryBar might expect flat list or user list.
        // Looking at MOCK_STORIES in StoryBar, it renders a list of items where each item has a user.
        // It seems simpler to return the raw stories and let the frontend group, 
        // OR return a list of "Story Bundles". 
        // Let's look at StoryBar.tsx again:
        // {MOCK_STORIES.map((story) => ( ... key={story.id} ... story.user.username ... ))}
        // This implies MOCK_STORIES is a list where each element is a User's story set? 
        // Or just individual stories?
        // If it's individual stories, then if a user has 5 stories, they appear 5 times in the bar?
        // That would be bad UI. Usually it's one circle per user.
        // I'll assume MOCK_STORIES was likely a list of "User Stories" objects.

        // Let's Group by User manually to ensure one item per user in the bar.
        const userStoriesMap = new Map();

        stories.forEach(story => {
            if (!userStoriesMap.has(story.userId)) {
                userStoriesMap.set(story.userId, {
                    id: story.userId, // Use userId as the key for the circle
                    user: story.user,
                    stories: [],
                    hasViewed: false, // Placeholder
                    latestAt: story.createdAt
                });
            }
            userStoriesMap.get(story.userId).stories.push(story);
        });

        // Convert to array and sort by latest story
        const groupedStories = Array.from(userStoriesMap.values()).sort((a, b) =>
            new Date(b.latestAt).getTime() - new Date(a.latestAt).getTime()
        );

        return NextResponse.json(groupedStories);
    } catch (error) {
        console.error('API Error (GET /api/stories):', error);
        // Fallback to mock stories when DB/Prisma isn't available
        try {
            const fallback = MOCK_STORIES.map(s => ({
                id: s.id,
                user: s.user,
                slides: s.slides,
                hasViewed: s.hasViewed,
            }));
            return NextResponse.json(fallback);
        } catch (err) {
            return NextResponse.json({ error: 'Failed to fetch stories' }, { status: 500 });
        }
    }
}

