const CreatePostPage = () => {
    const [mediaItems, setMediaItems] = useState<{ url: string; file?: File; type: 'image' | 'video' }[]>([]);
    const [currentMediaIndex, setCurrentMediaIndex] = useState(0);
    const [caption, setCaption] = useState('');
    const [activeFilter, setActiveFilter] = useState(FILTERS[0]);
    const [location, setLocation] = useState('');
    const [isPending, startTransition] = useTransition();
    const [isDragging, setIsDragging] = useState(false);
    const [isGeneratingCaption, setIsGeneratingCaption] = useState(false);
    const [isEnhancing, setIsEnhancing] = useState(false);
    const [isEnhanced, setIsEnhanced] = useState(false);
    const [currentUser, setCurrentUser] = useState<any>(null);
    const router = useRouter();

    useEffect(() => {
        const fetchMe = async () => {
            try {
                const res = await fetch('/api/users/me');
                if (res.ok) {
                    const data = await res.json();
                    setCurrentUser(data);
                }
            } catch (err) {
                console.error('Failed to fetch user', err);
            }
        };
        fetchMe();
    }, []);

    const handleAIEnhance = () => {
        setIsEnhancing(true);
        setTimeout(() => {
            setIsEnhancing(false);
            setIsEnhanced(!isEnhanced);
        }, 2000);
    };

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const files = Array.from(e.target.files || []);
        if (files.length > 0) {
            files.forEach(file => {
                if (!file.type.startsWith('image/') && !file.type.startsWith('video/')) return;
                const type: 'image' | 'video' = file.type.startsWith('video/') ? 'video' : 'image';
                const objectUrl = URL.createObjectURL(file);
                setMediaItems(prev => [...prev, { url: objectUrl, file, type }]);
            });
        }
    };

    const handleDrop = useCallback((e: React.DragEvent) => {
        e.preventDefault();
        setIsDragging(false);
        const files = Array.from(e.dataTransfer.files || []);
        if (files.length > 0) {
            files.forEach(file => {
                if (!file.type.startsWith('image/') && !file.type.startsWith('video/')) return;
                const type: 'image' | 'video' = file.type.startsWith('video/') ? 'video' : 'image';
                const objectUrl = URL.createObjectURL(file);
                setMediaItems(prev => [...prev, { url: objectUrl, file, type }]);
            });
        }
    }, []);

    const handleDragOver = useCallback((e: React.DragEvent) => {
        e.preventDefault();
        setIsDragging(true);
    }, []);

    const handleDragLeave = useCallback(() => {
        setIsDragging(false);
    }, []);

    const handleShare = async () => {
        if (mediaItems.length === 0) return;

        startTransition(async () => {
            try {
                const formData = new FormData();
                formData.append('caption', caption);
                formData.append('location', location);
                formData.append('filter', activeFilter.name);

                // Upload each media item sequentially
                for (let i = 0; i < mediaItems.length; i++) {
                    const item = mediaItems[i];
                    if (item.file) {
                        const res = await fetch('/api/uploads', {
                            method: 'POST',
                            headers: { 'Content-Type': 'application/json' },
                            body: JSON.stringify({ fileName: item.file.name, contentType: item.file.type })
                        });

                        if (!res.ok) throw new Error(`Failed to get upload URL for item ${i}`);
                        const data = await res.json();

                        const putRes = await fetch(data.uploadUrl, {
                            method: 'PUT',
                            headers: { 'Content-Type': item.file.type },
                            body: item.file
                        });

                        if (!putRes.ok) throw new Error(`Upload failed for item ${i}`);
                        formData.append(`media-${i}`, data.publicUrl);
                    } else {
                        formData.append(`media-${i}`, item.url);
                    }
                }

                await createPost(formData);
                router.push('/');
            } catch (error) {
                console.error('Failed to share post:', error);
                alert('Failed to share post: ' + (error as Error).message);
            }
        });
    };

    const generateAICaption = () => {
        setIsGeneratingCaption(true);
        setTimeout(() => {
            const mocks = [
                "Chasing sunsets and good vibes 🌅✨",
                "Wanderlust and city dust. #TravelDiaries",
                "POV: You're exactly where you need to be. 💫",
                "Life is better when you're laughing. 😂💖",
                "Art in every corner. 🎨🖌️"
            ];
            setCaption(mocks[Math.floor(Math.random() * mocks.length)]);
            setIsGeneratingCaption(false);
        }, 1500);
    };

    const handleLocationClick = () => {
        const places = ['New York, USA', 'Tokyo, Japan', 'Paris, France', 'London, UK'];
        setLocation(places[Math.floor(Math.random() * places.length)]);
    };

    return (
        <div className={styles.createPage}>
            <div className="neural-grid" />

            <motion.div
                className={styles.modal}
                initial={{ opacity: 0, scale: 0.9, y: 20 }}
                animate={{ opacity: 1, scale: 1, y: 0 }}
                transition={{ duration: 0.4, ease: [0.16, 1, 0.3, 1] }}
            >
                {/* Header */}
                <div className={styles.header}>
                    {mediaItems.length > 0 ? (
                        <motion.button
                            initial={{ opacity: 0, x: -10 }}
                            animate={{ opacity: 1, x: 0 }}
                            className={styles.backBtn}
                            onClick={() => setMediaItems([])}
                            disabled={isPending}
                        >
                            <ChevronLeft size={22} />
                        </motion.button>
                    ) : (
                        <button className={styles.closeBtn} onClick={() => router.back()} disabled={isPending}>
                            <X size={22} />
                        </button>
                    )}

                    <div className={styles.title}>
                        Create new post
                    </div>

                    {mediaItems.length > 0 ? (
                        <motion.button
                            initial={{ opacity: 0, x: 10 }}
                            animate={{ opacity: 1, x: 0 }}
                            className={styles.shareButton}
                            onClick={handleShare}
                            disabled={isPending}
                        >
                            {isPending ? <div className={styles.spinner} /> : 'Share'}
                        </motion.button>
                    ) : (
                        <div style={{ width: 40 }} />
                    )}
                </div>

                {/* Content */}
                <div
                    className={`${styles.content} ${isDragging ? styles.dragging : ''}`}
                    onDrop={handleDrop}
                    onDragOver={handleDragOver}
                    onDragLeave={handleDragLeave}
                >
                    {mediaItems.length > 0 ? (
                        <div className={styles.editorContainer}>
                            {/* Media Preview Side */}
                            <div className={styles.imagePreviewSection}>
                                <div className={styles.mainPreviewWrapper}>
                                    <AnimatePresence mode="wait">
                                        <motion.div
                                            key={mediaItems[currentMediaIndex].url}
                                            initial={{ opacity: 0, scale: 1.1 }}
                                            animate={{ opacity: 1, scale: 1 }}
                                            exit={{ opacity: 0, scale: 0.9 }}
                                            transition={{ duration: 0.4 }}
                                            className={styles.mainPreviewWrapper}
                                        >
                                            {mediaItems[currentMediaIndex].type === 'image' ? (
                                                <img
                                                    src={mediaItems[currentMediaIndex].url}
                                                    alt="Preview"
                                                    className={`${styles.previewImage} ${isEnhancing ? styles.enhancingScan : ''}`}
                                                    style={{ filter: isEnhanced ? 'contrast(1.1) saturate(1.2) brightness(1.05)' : activeFilter.value }}
                                                />
                                            ) : (
                                                <video
                                                    src={mediaItems[currentMediaIndex].url}
                                                    className={styles.previewImage}
                                                    style={{ filter: isEnhanced ? 'contrast(1.1) saturate(1.2)' : activeFilter.value }}
                                                    autoPlay
                                                    muted
                                                    loop
                                                />
                                            )}
                                        </motion.div>
                                    </AnimatePresence>

                                    {/* AI Enhance Button */}
                                    <button
                                        className={`${styles.aiEnhanceBtn} ${isEnhanced ? styles.aiActive : ''}`}
                                        onClick={handleAIEnhance}
                                        disabled={isEnhancing}
                                    >
                                        <Sparkles size={16} className={isEnhancing ? styles.spin : ''} />
                                        <span>{isEnhancing ? 'Enhancing...' : isEnhanced ? 'AI Enhanced' : 'AI Enhance'}</span>
                                    </button>
                                </div>

                                {mediaItems.length > 1 && (
                                    <div className={styles.carouselControls}>
                                        {currentMediaIndex > 0 && (
                                            <button className={styles.navBtnPrev} onClick={() => setCurrentMediaIndex(i => i - 1)}>
                                                <ChevronLeft size={20} />
                                            </button>
                                        )}
                                        {currentMediaIndex < mediaItems.length - 1 && (
                                            <button className={styles.navBtnNext} onClick={() => setCurrentMediaIndex(i => i + 1)}>
                                                <ChevronLeft size={20} style={{ transform: 'rotate(180deg)' }} />
                                            </button>
                                        )}
                                        <div className={styles.carouselDots}>
                                            {mediaItems.map((_, i) => (
                                                <div key={i} className={`${styles.dot} ${i === currentMediaIndex ? styles.activeDot : ''}`} />
                                            ))}
                                        </div>
                                    </div>
                                )}
                            </div>

                            {/* Sidebar Details Side */}
                            <div className={styles.detailsSidebar}>
                                {currentUser && (
                                    <div className={styles.userInfo}>
                                        <img src={currentUser.avatar || "https://i.pravatar.cc/150"} alt="Me" className={styles.avatar} />
                                        <span className={styles.username}>{currentUser.username}</span>
                                    </div>
                                )}

                                <div className={styles.captionArea}>
                                    <textarea
                                        className={styles.captionInput}
                                        placeholder="Write a caption..."
                                        value={caption}
                                        onChange={(e) => setCaption(e.target.value)}
                                        disabled={isPending}
                                        maxLength={2200}
                                    />
                                    <div className={styles.toolsRow}>
                                        <div style={{ display: 'flex', gap: 12 }}>
                                            <button className={styles.toolBtn} title="Add emoji">
                                                <Smile size={20} />
                                            </button>
                                            <button
                                                className={`${styles.toolBtn} ${isGeneratingCaption ? styles.sparkleLoading : ''}`}
                                                title="AI Magic Caption"
                                                onClick={generateAICaption}
                                                disabled={isGeneratingCaption}
                                            >
                                                <Sparkles size={20} color={isGeneratingCaption ? "var(--primary)" : "currentColor"} />
                                            </button>
                                        </div>
                                        <div className={styles.charCount}>{caption.length}/2,200</div>
                                    </div>
                                </div>

                                <div className={styles.optionsList}>
                                    <div className={styles.optionItem} onClick={handleLocationClick}>
                                        <span className={styles.optionLabel}>Add Location</span>
                                        {location ? (
                                            <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
                                                <MapPin size={14} color="var(--primary)" />
                                                <span className={styles.optionValue}>{location}</span>
                                            </div>
                                        ) : (
                                            <MapPin size={20} color="white" />
                                        )}
                                    </div>
                                    <div className={styles.optionItem}>
                                        <span className={styles.optionLabel}>Tag People</span>
                                        <ChevronDown size={20} color="white" />
                                    </div>
                                    <div className={styles.optionItem}>
                                        <span className={styles.optionLabel}>Advanced settings</span>
                                        <ChevronDown size={20} color="white" />
                                    </div>
                                </div>

                                {/* Filters */}
                                <div className={styles.filtersSection}>
                                    <div className={styles.filtersTitle}>Filters</div>
                                    <div className={styles.filtersGrid}>
                                        {FILTERS.map((filter) => (
                                            <div
                                                key={filter.name}
                                                className={`${styles.filterItem} ${activeFilter.name === filter.name ? styles.active : ''}`}
                                                onClick={() => setActiveFilter(filter)}
                                            >
                                                <div className={styles.filterPreview}>
                                                    {mediaItems[currentMediaIndex].type === 'image' ? (
                                                        <img
                                                            src={mediaItems[currentMediaIndex].url}
                                                            alt={filter.name}
                                                            style={{ filter: filter.value }}
                                                        />
                                                    ) : (
                                                        <div className={styles.videoFilterPlaceholder}>
                                                            <Upload size={16} />
                                                        </div>
                                                    )}
                                                </div>
                                                <span className={styles.filterName}>{filter.name}</span>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            </div>
                        </div>
                    ) : (
                        <motion.div
                            className={styles.uploadArea}
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                        >
                            <div className={styles.uploadIconWrap}>
                                <Upload size={48} strokeWidth={1.5} />
                            </div>
                            <div className={styles.uploadText}>Experience the future of sharing</div>
                            <label className={styles.selectButton}>
                                Select from computer
                                <input type="file" hidden onChange={handleFileChange} accept="image/*,video/*" multiple />
                            </label>
                        </motion.div>
                    )}
                </div>
            </motion.div>
        </div>
    );
};

export default CreatePostPage;

