'use client';

import React, { useState, useTransition } from 'react';
import {
    Heart,
    MessageCircle,
    Send,
    Bookmark,
    MoreHorizontal,
    UserPlus,
    UserMinus,
    Zap
} from 'lucide-react';
import styles from './Post.module.css';
import { toggleLike, toggleShotLike, toggleSavedPost, toggleSavedShot, addComment, addShotComment } from '@/app/actions';
import { formatDistanceToNow } from 'date-fns';
import { motion, AnimatePresence } from 'framer-motion';
import { useTheme } from '@/contexts/ThemeContext';

interface PostProps {
    id: string;
    type?: 'post' | 'shot';
    user: {
        username: string;
        avatar?: string | null;
    };
    image?: string;
    video?: string;
    likes: number;
    isLiked?: boolean;
    caption: string;
    time: string;
    media?: Array<{ url: string; type: string; order: number }>;
    comments?: Array<{
        id: string;
        text: string;
        user: {
            username: string;
            avatar?: string;
        };
        createdAt: string;
    }>;
}

const Post: React.FC<PostProps> = ({ id, type = 'post', user, image, video, media = [], likes, isLiked: initialIsLiked, caption, time, comments = [] }) => {
    const { isHologram } = useTheme();
    const [isLiked, setIsLiked] = useState(initialIsLiked || false);
    const [localLikes, setLocalLikes] = useState(likes);
    const [isPending, startTransition] = useTransition();
    const [showHeart, setShowHeart] = useState(false);
    const [isSaved, setIsSaved] = useState(false);
    const [isFollowingAuthor, setIsFollowingAuthor] = useState(false);
    const [imageLoaded, setImageLoaded] = useState(false);
    const [showComments, setShowComments] = useState(false);
    const [comment, setComment] = useState('');
    const [localComments, setLocalComments] = useState(comments);
    const [captionExpanded, setCaptionExpanded] = useState(false);
    const [currentMediaIndex, setCurrentMediaIndex] = useState(0);
    const videoRef = React.useRef<HTMLVideoElement>(null);

    const handleLike = async () => {
        const newIsLiked = !isLiked;
        setIsLiked(newIsLiked);
        setLocalLikes(prev => newIsLiked ? prev + 1 : prev - 1);

        if (newIsLiked) {
            setShowHeart(true);
            setTimeout(() => setShowHeart(false), 1000);
        }

        startTransition(async () => {
            try {
                if (type === 'shot' || video) {
                    await toggleShotLike(id);
                } else {
                    await toggleLike(id);
                }
            } catch (error) {
                setIsLiked(!newIsLiked);
                setLocalLikes(prev => !newIsLiked ? prev + 1 : prev - 1);
                console.error('Failed to toggle like:', error);
            }
        });
    };

    // Auto-play video on intersect could be added here, but simple controls or autoplay loop is fine for now

    // ... comment and share handlers ...

    const handleComment = () => {
        if (comment.trim()) {
            const newComment = {
                id: Date.now().toString(),
                text: comment,
                user: { username: 'You', avatar: '' }, // Optimistic user
                createdAt: new Date().toISOString()
            };
            setLocalComments([...localComments, newComment]);
            setComment('');

            startTransition(async () => {
                try {
                    if (type === 'shot' || video) {
                        await addShotComment(id, newComment.text);
                    } else {
                        await addComment(id, newComment.text);
                    }
                } catch (error) {
                    console.error('Failed to post comment:', error);
                    // Revert optimistic update
                    setLocalComments(prev => prev.filter(c => c.id !== newComment.id));
                }
            });
        }
    };

    const handleSave = () => {
        const newIsSaved = !isSaved;
        setIsSaved(newIsSaved);

        startTransition(async () => {
            try {
                if (type === 'shot' || video) {
                    await toggleSavedShot(id);
                } else {
                    await toggleSavedPost(id);
                }
            } catch (error) {
                setIsSaved(!newIsSaved);
                console.error('Failed to toggle save:', error);
            }
        });
    };

    const handleFollow = () => {
        const next = !isFollowingAuthor;
        setIsFollowingAuthor(next);

        startTransition(async () => {
            try {
                const { toggleFollow } = await import('@/app/actions');
                await toggleFollow(user.username);
            } catch (err) {
                console.error('Follow toggle failed', err);
                setIsFollowingAuthor(!next);
            }
        });
    };

    const handleShare = () => {
        if (navigator.share) {
            navigator.share({
                title: `Post by ${user.username}`,
                text: caption,
                url: window.location.href,
            }).catch(() => {
                navigator.clipboard.writeText(window.location.href);
                alert('Link copied to clipboard!');
            });
        } else {
            navigator.clipboard.writeText(window.location.href);
            alert('Link copied to clipboard!');
        }
    };

    const formatLikes = (count: number) => {
        if (count >= 1000000) return `${(count / 1000000).toFixed(1)}M`;
        if (count >= 1000) return `${(count / 1000).toFixed(1)}K`;
        return count.toLocaleString();
    };

    return (
        <motion.article
            layout
            className={styles.post}
            variants={{
                hidden: { opacity: 0, y: 20 },
                show: { opacity: 1, y: 0, transition: { type: 'spring', stiffness: 300, damping: 24 } }
            }}
            initial="hidden"
            animate="show"
            exit={{ opacity: 0, scale: 0.95, transition: { duration: 0.2 } }}
        >
            {/* Header */}
            <div className={styles.header}>
                <div className={styles.userInfo}>
                    <div className={styles.avatarRing}>
                        <img src={user.avatar || 'https://i.pravatar.cc/150'} alt={user.username} className={styles.avatar} />
                    </div>
                    <div className={styles.userMeta}>
                        <span className={styles.username}>{user.username}</span>
                        <span className={styles.time}>{time}</span>
                    </div>
                </div>
                <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
                    <button className={styles.followBtn} onClick={(e) => { e.stopPropagation(); handleFollow(); }}>
                        {isFollowingAuthor ? <UserMinus size={16} /> : <UserPlus size={16} />}
                        <span style={{ marginLeft: 6 }}>{isFollowingAuthor ? 'Following' : 'Follow'}</span>
                    </button>
                    <button className={styles.moreBtn}>
                        <MoreHorizontal size={20} />
                    </button>
                </div>
            </div>

            {/* Content (Image or Video) */}
            <div className={styles.imageContainer} onDoubleClick={handleLike}>
                {!imageLoaded && !video && (
                    <div className={`${styles.imageSkeleton} skeleton`}></div>
                )}

                <div className={styles.mediaCarousel}>
                    <AnimatePresence mode="wait">
                        <motion.div
                            key={media.length > 0 ? media[currentMediaIndex]?.url : (image || video)}
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            className={styles.mediaWrapper}
                        >
                            {(media[currentMediaIndex]?.type === 'VIDEO' || video) ? (
                                <video
                                    ref={videoRef}
                                    src={media.length > 0 ? media[currentMediaIndex].url : video}
                                    className={styles.postImage}
                                    autoPlay
                                    muted
                                    loop
                                    playsInline
                                    onLoadedData={() => setImageLoaded(true)}
                                />
                            ) : (
                                <img
                                    src={media.length > 0 ? media[currentMediaIndex].url : image}
                                    alt="Post content"
                                    className={`${styles.postImage} ${imageLoaded ? styles.loaded : ''}`}
                                    loading="lazy"
                                    onLoad={() => setImageLoaded(true)}
                                />
                            )}
                        </motion.div>
                    </AnimatePresence>

                    {media.length > 1 && (
                        <>
                            {currentMediaIndex > 0 && (
                                <button className={styles.carouselBtnPrev} onClick={() => setCurrentMediaIndex(i => i - 1)}>
                                    ‹
                                </button>
                            )}
                            {currentMediaIndex < media.length - 1 && (
                                <button className={styles.carouselBtnNext} onClick={() => setCurrentMediaIndex(i => i + 1)}>
                                    ›
                                </button>
                            )}
                            <div className={styles.carouselDots}>
                                {media.map((_, i) => (
                                    <div key={i} className={`${styles.dot} ${i === currentMediaIndex ? styles.activeDot : ''}`} />
                                ))}
                            </div>
                        </>
                    )}
                </div>

                <AnimatePresence>
                    {showHeart && (
                        <motion.div
                            className={styles.largeHeart}
                            initial={{ scale: 0, opacity: 0 }}
                            animate={{ scale: 1.2, opacity: 1 }}
                            exit={{ scale: 0, opacity: 0 }}
                            transition={{ type: "spring", stiffness: 400, damping: 12 }}
                        >
                            <Heart size={80} fill="white" color="white" />
                        </motion.div>
                    )}
                </AnimatePresence>
            </div>

            {/* Actions */}
            <div className={styles.actions}>
                <div className={styles.leftActions}>
                    <motion.button
                        whileTap={{ scale: 0.75 }}
                        className={`${styles.actionButton} ${isLiked ? styles.liked : ''}`}
                        onClick={handleLike}
                        disabled={isPending}
                    >
                        <Heart size={24} fill={isLiked ? '#ed4956' : 'none'} color={isLiked ? '#ed4956' : 'currentColor'} />
                    </motion.button>
                    <motion.button
                        whileTap={{ scale: 0.75 }}
                        className={styles.actionButton}
                        onClick={() => setShowComments(!showComments)}
                    >
                        <MessageCircle size={24} />
                    </motion.button>
                    <motion.button
                        whileTap={{ scale: 0.75 }}
                        className={styles.actionButton}
                        onClick={handleShare}
                    >
                        <Send size={22} />
                    </motion.button>
                </div>
                <motion.button
                    whileTap={{ scale: 0.75 }}
                    className={`${styles.actionButton} ${isSaved ? styles.saved : ''}`}
                    onClick={handleSave}
                >
                    <Bookmark size={24} fill={isSaved ? 'currentColor' : 'none'} />
                </motion.button>
            </div>

            {/* Engagement */}
            <div className={styles.engagement}>
                <div className={styles.likes}>{formatLikes(localLikes)} likes</div>
                <div className={styles.caption}>
                    <span className={styles.captionUser}>{user.username}</span>
                    {caption.length > 100 && !captionExpanded ? (
                        <>
                            {caption.substring(0, 100)}...{' '}
                            <button
                                className={styles.moreBtn}
                                onClick={() => setCaptionExpanded(true)}
                            >
                                more
                            </button>
                        </>
                    ) : (
                        caption
                    )}
                </div>
                <button
                    className={styles.viewComments}
                    onClick={() => setShowComments(!showComments)}
                >
                    View all comments
                </button>
            </div>

            {/* Comment Input */}
            <AnimatePresence>
                {showComments && (
                    <motion.div
                        className={styles.commentSection}
                        initial={{ height: 0, opacity: 0 }}
                        animate={{ height: 'auto', opacity: 1 }}
                        exit={{ height: 0, opacity: 0 }}
                        transition={{ duration: 0.3 }}
                    >
                        {localComments && localComments.length > 0 && (
                            <div className={styles.commentList}>
                                {localComments.map((c) => (
                                    <div key={c.id} className={styles.comment}>
                                        <div className={styles.commentContent}>
                                            <div>
                                                <span className={styles.commentUser}>{c.user.username}</span>
                                                <span className={styles.commentText}>{c.text}</span>
                                            </div>
                                            <span className={styles.commentTime}>
                                                {formatDistanceToNow(new Date(c.createdAt), { addSuffix: true })}
                                            </span>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        )}
                        <div className={styles.commentInput}>
                            <input
                                type="text"
                                placeholder="Add a comment..."
                                value={comment}
                                onChange={(e) => setComment(e.target.value)}
                                onKeyPress={(e) => e.key === 'Enter' && handleComment()}
                                className={styles.input}
                            />
                            {comment.trim() && (
                                <motion.button
                                    initial={{ scale: 0 }}
                                    animate={{ scale: 1 }}
                                    className={styles.postBtn}
                                    onClick={handleComment}
                                >
                                    Post
                                </motion.button>
                            )}
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>
        </motion.article>
    );
};

export default Post;

'use client';

import React, { useState } from 'react';
import { motion } from 'framer-motion';
import styles from './StoryBar.module.css';
import { Plus } from 'lucide-react';
// import { MOCK_STORIES } from '@/constants/mockData';
import StoryViewer from '../modals/StoryViewer';

const StoryBar = () => {
    const [stories, setStories] = useState<any[]>([]);
    const [viewerStories, setViewerStories] = useState<any[]>([]);
    const [selectedStoryIndex, setSelectedStoryIndex] = useState<number | null>(null);

    React.useEffect(() => {
        const fetchStories = async () => {
            try {
                const res = await fetch('/api/stories');
                const data = await res.json();
                if (Array.isArray(data)) {
                    setStories(data);
                    // Flatten for viewer
                    const flat = data.flatMap((group: any) => group.stories.map((s: any) => ({ ...s, user: group.user })));
                    setViewerStories(flat);
                }
            } catch (err) {
                console.error('Failed to fetch stories', err);
            }
        };
        fetchStories();
    }, []);

    const handleStoryClick = (userIndex: number) => {
        // Find the index in the flat list where this user's stories start
        if (!stories[userIndex]) return;
        const firstStoryId = stories[userIndex].stories[0]?.id;
        const flatIndex = viewerStories.findIndex(s => s.id === firstStoryId);
        setSelectedStoryIndex(flatIndex >= 0 ? flatIndex : 0);
    };

    const containerVariants = {
        hidden: { opacity: 0 },
        show: {
            opacity: 1,
            transition: {
                staggerChildren: 0.05
            }
        }
    };

    const itemVariants = {
        hidden: { opacity: 0, x: -10 },
        show: { opacity: 1, x: 0 }
    };

    return (
        <>
            <motion.div
                className={styles.storyBar}
                variants={containerVariants}
                initial="hidden"
                animate="show"
            >
                {/* Your Story */}
                <motion.div className={styles.storyContainer} variants={itemVariants}>
                    <div className={`${styles.storyCircle} ${styles.yourStory}`}>
                        <img src="https://i.pravatar.cc/150?u=me" alt="Your story" className={styles.avatar} />
                        <div className={styles.plusBadge}>
                            <Plus size={12} strokeWidth={3} />
                        </div>
                    </div>
                    <span className={styles.username}>Your story</span>
                </motion.div>

                {stories.map((group, index) => (
                    <motion.div
                        key={group.user.username}
                        className={styles.storyContainer}
                        variants={itemVariants}
                        onClick={() => handleStoryClick(index)}
                        whileHover={{ scale: 1.05 }}
                        whileTap={{ scale: 0.95 }}
                    >
                        {/* Check if any story in group is unseen, for now assume all fresh */}
                        <div className={`${styles.storyCircle} ${styles.hasNew}`}>
                            <img src={group.user.avatar} alt={group.user.username} className={styles.avatar} />
                        </div>
                        <span className={styles.username}>{group.user.username}</span>
                    </motion.div>
                ))}
            </motion.div>

            {selectedStoryIndex !== null && viewerStories.length > 0 && (
                <StoryViewer
                    stories={viewerStories}
                    initialStoryIndex={selectedStoryIndex}
                    isOpen={selectedStoryIndex !== null}
                    onClose={() => setSelectedStoryIndex(null)}
                />
            )}
        </>
    );
};

export default StoryBar;

'use client';

import React from 'react';
import Link from 'next/link';
// import { MOCK_USERS } from '@/constants/mockData';
import styles from './RightSidebar.module.css';
import { useState, useEffect } from 'react';

const RightSidebar = () => {
    const [currentUser, setCurrentUser] = useState<any>(null);
    const [suggestions, setSuggestions] = useState<any[]>([]);

    useEffect(() => {
        const fetchData = async () => {
            try {
                // Fetch Me
                const meRes = await fetch('/api/users/me');
                if (meRes.ok) {
                    const meData = await meRes.json();
                    setCurrentUser(meData);
                }

                // Fetch Suggestions (all users for now, filter out me)
                const usersRes = await fetch('/api/users');
                if (usersRes.ok) {
                    const allUsers = await usersRes.json();
                    // Simple logic: take first 5 that are not me
                    setSuggestions(allUsers.filter((u: any) => u.id !== currentUser?.id).slice(0, 5));
                }
            } catch (err) {
                console.error('RightSidebar fetch error', err);
            }
        };
        fetchData();
    }, []);

    if (!currentUser) return null; // Or a skeleton

    return (
        <aside className={styles.rightSidebar}>
            {/* Current User */}
            <div className={styles.userProfile}>
                <Link href="/profile" className={styles.userInfo}>
                    <img
                        src={currentUser.avatar || "https://i.pravatar.cc/150"}
                        alt={currentUser.username}
                        className={styles.avatar}
                    />
                    <div className={styles.userDetails}>
                        <div className={styles.username}>{currentUser.username}</div>
                        <div className={styles.fullName}>{currentUser.fullName || currentUser.username}</div>
                    </div>
                </Link>
                <button className={styles.switchBtn}>Switch</button>
            </div>

            {/* Suggestions Header */}
            <div className={styles.suggestionsHeader}>
                <div className={styles.suggestionsTitle}>Suggested for you</div>
                <button className={styles.seeAllBtn}>See All</button>
            </div>

            {/* Suggestions List */}
            <div className={styles.suggestionsList}>
                {suggestions.map((user) => (
                    <div key={user.id} className={styles.suggestionItem}>
                        <div className={styles.suggestionUserInfo}>
                            <Link href={`/${user.username}`}>
                                <img
                                    src={user.avatar || `https://i.pravatar.cc/150?u=${user.username}`}
                                    alt={user.username}
                                    className={styles.suggestionAvatar}
                                />
                            </Link>
                            <div className={styles.suggestionDetails}>
                                <Link href={`/${user.username}`} className={styles.suggestionUsername}>
                                    {user.username}
                                </Link>
                                <div className={styles.suggestionMeta}>Suggested for you</div>
                            </div>
                        </div>
                        <button className={styles.followBtn}>Follow</button>
                    </div>
                ))}
            </div>

            {/* App Stores */}
            <div className={styles.appStoreSection}>
                <div className={styles.appStoreTitle}>Get the App</div>
                <div className={styles.storeButtons}>
                    <img
                        src="https://upload.wikimedia.org/wikipedia/commons/3/3c/Download_on_the_App_Store_Badge.svg"
                        alt="Download on the App Store"
                        className={styles.storeBadge}
                    />
                    <img
                        src="https://upload.wikimedia.org/wikipedia/commons/7/78/Google_Play_Store_badge_EN.svg"
                        alt="Get it on Google Play"
                        className={styles.storeBadge}
                    />
                </div>
            </div>


            {/* Tech Stack Info */}
            <div className={styles.techInfo}>
                <span className={styles.techLabel}>Databases</span>
                PostgreSQL is used as the primary relational database for structured data like user profiles and comments, while Cassandra is used for highly distributed data like activity logs and analytics.
            </div>

        </aside>
    );
};

export default RightSidebar;

