import React, { useState } from 'react';
import { X, Key, Eye, EyeOff, Check } from 'lucide-react';
import styles from './ChangePasswordModal.module.css';

interface ChangePasswordModalProps {
    isOpen: boolean;
    onClose: () => void;
}

const ChangePasswordModal: React.FC<ChangePasswordModalProps> = ({ isOpen, onClose }) => {
    const [currentPassword, setCurrentPassword] = useState('');
    const [newPassword, setNewPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [showCurrentPassword, setShowCurrentPassword] = useState(false);
    const [showNewPassword, setShowNewPassword] = useState(false);
    const [showConfirmPassword, setShowConfirmPassword] = useState(false);
    const [error, setError] = useState('');

    if (!isOpen) return null;

    // Password requirements
    const hasMinLength = newPassword.length >= 8;
    const hasUpperCase = /[A-Z]/.test(newPassword);
    const hasLowerCase = /[a-z]/.test(newPassword);
    const hasNumber = /[0-9]/.test(newPassword);
    const hasSpecialChar = /[!@#$%^&*(),.?":{}|<>]/.test(newPassword);

    const isPasswordValid = hasMinLength && hasUpperCase && hasLowerCase && hasNumber;

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        setError('');

        if (!currentPassword) {
            setError('Please enter your current password');
            return;
        }

        if (!isPasswordValid) {
            setError('New password does not meet requirements');
            return;
        }

        if (newPassword !== confirmPassword) {
            setError('New passwords do not match');
            return;
        }

        // In a real app, this would call an API
        console.log('Password change submitted');
        alert('Password changed successfully! 🔒');
        onClose();

        // Reset form
        setCurrentPassword('');
        setNewPassword('');
        setConfirmPassword('');
    };

    return (
        <div className={styles.overlay} onClick={onClose}>
            <div className={styles.modal} onClick={e => e.stopPropagation()}>
                <div className={styles.header}>
                    <div className={styles.title}>
                        <Key size={20} />
                        <h2>Change Password</h2>
                    </div>
                    <button className={styles.closeBtn} onClick={onClose}>
                        <X size={24} />
                    </button>
                </div>

                <form className={styles.form} onSubmit={handleSubmit}>
                    <div className={styles.inputGroup}>
                        <label className={styles.label}>Current Password</label>
                        <div className={styles.inputWrapper}>
                            <input
                                type={showCurrentPassword ? 'text' : 'password'}
                                value={currentPassword}
                                onChange={(e) => setCurrentPassword(e.target.value)}
                                className={styles.input}
                                placeholder="Enter current password"
                            />
                            <button
                                type="button"
                                className={styles.togglePassword}
                                onClick={() => setShowCurrentPassword(!showCurrentPassword)}
                            >
                                {showCurrentPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                            </button>
                        </div>
                    </div>

                    <div className={styles.inputGroup}>
                        <label className={styles.label}>New Password</label>
                        <div className={styles.inputWrapper}>
                            <input
                                type={showNewPassword ? 'text' : 'password'}
                                value={newPassword}
                                onChange={(e) => setNewPassword(e.target.value)}
                                className={styles.input}
                                placeholder="Enter new password"
                            />
                            <button
                                type="button"
                                className={styles.togglePassword}
                                onClick={() => setShowNewPassword(!showNewPassword)}
                            >
                                {showNewPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                            </button>
                        </div>
                        {newPassword && (
                            <div className={styles.requirements}>
                                <div className={`${styles.requirement} ${hasMinLength ? styles.met : ''}`}>
                                    {hasMinLength ? <Check size={14} /> : '•'} At least 8 characters
                                </div>
                                <div className={`${styles.requirement} ${hasUpperCase ? styles.met : ''}`}>
                                    {hasUpperCase ? <Check size={14} /> : '•'} One uppercase letter
                                </div>
                                <div className={`${styles.requirement} ${hasLowerCase ? styles.met : ''}`}>
                                    {hasLowerCase ? <Check size={14} /> : '•'} One lowercase letter
                                </div>
                                <div className={`${styles.requirement} ${hasNumber ? styles.met : ''}`}>
                                    {hasNumber ? <Check size={14} /> : '•'} One number
                                </div>
                            </div>
                        )}
                    </div>

                    <div className={styles.inputGroup}>
                        <label className={styles.label}>Confirm New Password</label>
                        <div className={styles.inputWrapper}>
                            <input
                                type={showConfirmPassword ? 'text' : 'password'}
                                value={confirmPassword}
                                onChange={(e) => setConfirmPassword(e.target.value)}
                                className={`${styles.input} ${confirmPassword && newPassword !== confirmPassword ? styles.error : ''}`}
                                placeholder="Confirm new password"
                            />
                            <button
                                type="button"
                                className={styles.togglePassword}
                                onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                            >
                                {showConfirmPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                            </button>
                        </div>
                        {confirmPassword && newPassword !== confirmPassword && (
                            <div className={styles.errorText}>Passwords do not match</div>
                        )}
                    </div>

                    {error && <div className={styles.errorText}>{error}</div>}

                    <div className={styles.footer}>
                        <button type="button" className="btn-secondary" onClick={onClose}>Cancel</button>
                        <button type="submit" className="btn-primary" disabled={!isPasswordValid || newPassword !== confirmPassword}>
                            Change Password
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default ChangePasswordModal;

import React, { useState } from 'react';
import { X, Camera, Globe, Lock, ShieldCheck, Sparkles } from 'lucide-react';
import styles from './EditProfileModal.module.css';

interface EditProfileModalProps {
    isOpen: boolean;
    onClose: () => void;
    initialData: {
        username: string;
        fullName: string;
        bio: string;
        avatar: string;
        website?: string;
        category?: string;
        isPrivate?: boolean;
    };
    onSave: (data: any) => void;
}

const CATEGORIES = [
    'None',
    'Artist',
    'Blogger',
    'Digital Creator',
    'Education',
    'Entrepreneur',
    'Health/Beauty',
    'Editor',
    'Writer',
    'Personal Blog'
];

const EditProfileModal: React.FC<EditProfileModalProps> = ({ isOpen, onClose, initialData, onSave }) => {
    const [formData, setFormData] = useState({
        ...initialData,
        website: initialData.website || '',
        category: initialData.category || 'Digital Creator',
        isPrivate: initialData.isPrivate || false
    });

    if (!isOpen) return null;

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
        const { name, value, type } = e.target;
        const val = type === 'checkbox' ? (e.target as HTMLInputElement).checked : value;

        setFormData(prev => ({
            ...prev,
            [name]: val
        }));
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        onSave(formData);
        onClose();
    };

    return (
        <div className={styles.overlay} onClick={onClose}>
            <div className={styles.modal} onClick={e => e.stopPropagation()}>
                <div className={styles.header}>
                    <h2 className={styles.title}>Edit Profile</h2>
                    <button className={styles.closeBtn} onClick={onClose}>
                        <X size={20} />
                    </button>
                </div>

                <form onSubmit={handleSubmit} style={{ display: 'contents' }}>
                    <div className={styles.scrollArea}>
                        {/* Avatar Section */}
                        <div className={styles.avatarSection}>
                            <div className={styles.avatarContainer} onClick={() => document.getElementById('avatar-input')?.click()}>
                                <img src={formData.avatar} alt="Avatar" className={styles.avatar} />
                                <div className={styles.avatarOverlay}>
                                    <Camera size={24} />
                                </div>
                            </div>
                            <span className={styles.changePhotoText} onClick={() => document.getElementById('avatar-input')?.click()}>
                                Change profile photo
                            </span>
                            <input
                                id="avatar-input"
                                type="file"
                                hidden
                                accept="image/*"
                                onChange={() => {
                                    const url = prompt("Enter image URL:", formData.avatar);
                                    if (url) setFormData(p => ({ ...p, avatar: url }));
                                }}
                            />
                        </div>

                        {/* Personal Info Section */}
                        <div className={styles.section}>
                            <div className={styles.sectionHeader}>
                                <span className={styles.sectionTitle}>Profile Info</span>
                            </div>

                            <div className={styles.inputGroup}>
                                <label className={styles.label}>Name</label>
                                <input
                                    type="text"
                                    name="fullName"
                                    value={formData.fullName}
                                    onChange={handleChange}
                                    className={styles.input}
                                    placeholder="Full Name"
                                />
                            </div>

                            <div className={styles.inputGroup}>
                                <label className={styles.label}>Username</label>
                                <input
                                    type="text"
                                    name="username"
                                    value={formData.username}
                                    onChange={handleChange}
                                    className={styles.input}
                                    placeholder="Username"
                                />
                            </div>

                            <div className={styles.inputGroup}>
                                <label className={styles.label}>Website</label>
                                <div style={{ position: 'relative' }}>
                                    <Globe size={16} style={{ position: 'absolute', left: '12px', top: '50%', transform: 'translateY(-50%)', color: 'var(--foreground-muted)' }} />
                                    <input
                                        type="text"
                                        name="website"
                                        value={formData.website}
                                        onChange={handleChange}
                                        className={styles.input}
                                        style={{ paddingLeft: '38px' }}
                                        placeholder="https://example.com"
                                    />
                                </div>
                            </div>

                            <div className={styles.inputGroup}>
                                <label className={styles.label}>Bio</label>
                                <textarea
                                    name="bio"
                                    value={formData.bio}
                                    onChange={handleChange}
                                    className={styles.textarea}
                                    placeholder="Write a bio..."
                                    maxLength={150}
                                />
                            </div>
                        </div>

                        {/* Professional Section */}
                        <div className={styles.section}>
                            <div className={styles.sectionHeader}>
                                <span className={styles.sectionTitle}>Professional Tools</span>
                            </div>

                            <div className={styles.inputGroup}>
                                <label className={styles.label}>Category</label>
                                <select
                                    name="category"
                                    value={formData.category}
                                    onChange={handleChange}
                                    className={styles.select}
                                >
                                    {CATEGORIES.map(cat => (
                                        <option key={cat} value={cat}>{cat}</option>
                                    ))}
                                </select>
                            </div>
                        </div>

                        {/* Advanced/Privacy Section */}
                        <div className={styles.section}>
                            <div className={styles.sectionHeader}>
                                <span className={styles.sectionTitle}>Privacy & Safety</span>
                            </div>

                            <div className={styles.toggleItem}>
                                <div className={styles.toggleInfo}>
                                    <span className={styles.toggleTitle}>Private Account</span>
                                    <span className={styles.toggleDescription}>When your account is private, only people you approve can see your photos and videos.</span>
                                </div>
                                <label className={styles.switch}>
                                    <input
                                        type="checkbox"
                                        name="isPrivate"
                                        checked={formData.isPrivate}
                                        onChange={handleChange}
                                    />
                                    <span className={styles.slider}></span>
                                </label>
                            </div>

                            <div className={styles.toggleItem}>
                                <div className={styles.toggleInfo}>
                                    <span className={styles.toggleTitle}>Show Verification Badge</span>
                                    <span className={styles.toggleDescription}>Display a silver or gold checkmark based on your influence score.</span>
                                </div>
                                <ShieldCheck size={24} color="var(--primary)" />
                            </div>
                        </div>
                    </div>

                    <div className={styles.footer}>
                        <button type="button" className={styles.cancelBtn} onClick={onClose}>Cancel</button>
                        <button type="submit" className={styles.saveBtn}>Save Changes</button>
                    </div>
                </form>
            </div>
        </div>
    );
};

